const body = $json.body || $json;
const data = body.data || body;
const key = data.key || {};
const message = data.message || {};
const pushName = data.pushName || body.pushName || null;
const remoteJid = key.remoteJid || data.remoteJid || body.remoteJid || '';
const phone = String(remoteJid).replace(/@s\.whatsapp\.net|@c\.us|\D/g, '');
const text = message.conversation || message.extendedTextMessage?.text || message.imageMessage?.caption || message.audioMessage?.caption || data.text || body.text || '';
let messageType = 'text';
if (message.audioMessage) messageType = 'audio';
if (message.imageMessage) messageType = 'image';
if (!phone) throw new Error('Telefone nao encontrado no payload da Evolution API.');
return [{ json: { phone, customer_name: pushName, content: text, message_type: messageType, raw: body } }];

const conversation = $node['Buscar ou criar conversa'].json[0];
const input = $node['Normalizar mensagem'].json;
const prompt = `Voce e uma atendente da Clinica Sorriso Prime, uma clinica odontologica.

Regras:
- Responda em portugues do Brasil, de forma profissional, curta e humanizada.
- Se o cliente pedir preco/orcamento, explique que depende do procedimento e ofereca avaliacao.
- Se pedir agendamento, peca nome, melhor dia e horario.
- Se pedir humano, sinalize transferencia.
- Se encerrar conversa, agradeca e finalize.
- Classifique intent como: orçamento, agendamento, dúvidas, humano ou outros.
- Classifique sentiment como: positivo, neutro, negativo ou urgente.
- Marque needs_human true quando houver urgencia, dor intensa, reclamacao ou pedido de humano.

Responda APENAS JSON valido no formato:
{
  "reply": "texto para enviar no WhatsApp",
  "intent": "orçamento|agendamento|dúvidas|humano|outros",
  "sentiment": "positivo|neutro|negativo|urgente",
  "status": "em_andamento|aguardando_humano|encerrada",
  "needs_human": true
}

Cliente: ${input.customer_name || 'sem nome'}
Telefone: ${input.phone}
Status atual: ${conversation.status}
Mensagem recebida: ${input.content}`;
return [{ json: { prompt } }];

const response = $json;
const fallback = {
  reply: 'Obrigada pelo contato com a Clinica Sorriso Prime. Vou encaminhar sua mensagem para nossa equipe e ja retornamos por aqui.',
  intent: 'outros',
  sentiment: 'neutro',
  status: 'aguardando_humano',
  needs_human: true
};
try {
  const raw = response.candidates?.[0]?.content?.parts?.[0]?.text;
  const parsed = typeof raw === 'string' ? JSON.parse(raw) : fallback;
  return [{ json: { ...fallback, ...parsed, gemini_raw: response } }];
} catch (error) {
  return [{ json: { ...fallback, gemini_error: String(error), gemini_raw: response } }];
}
